insert into public.entreprises (name, slug, zone, region, city, country, metier, metier_label, color, initials, founded, certifications, address, phone, email, website, description, long_description, adf_url) values
  ('Atelier Louis Del Boca', 'atelier-louis-del-boca', 'France', 'Île-de-France', 'Suresnes', 'France', 'Peinture & Décors', 'Staff · Gypserie · Peinture décorative · Dorure · Maçonnerie', '#6B4F2A', 'DB', '1931', ARRAY['EPV','GMH'], '25 bis, rue Émile Duclaux, 92150 Suresnes', '+33 (0)1 41 38 17 17', 'contact@delboca.fr', 'http://www.delboca.fr', 'Depuis 1931, l''Atelier Louis Del Boca perpétue les traditions de styles et techniques à la Française : staff, gypserie, peinture décorative, dorure à la feuille et maçonnerie de haute qualité.', 'Depuis 1931, l''Atelier Louis Del Boca est réputé pour l''excellence de ses réalisations en staff, peinture décorative et maçonnerie. Ses compagnons maîtrisent les techniques héritées du XIXe siècle.', 'https://ateliersdefrance.com/entreprises/atelier-louis-del-boca/'),
  ('H. Chevalier', 'h-chevalier', 'France', 'Île-de-France', 'Suresnes', 'France', 'Pierre & Maçonnerie', 'Taille de pierre · Maçonnerie · Gros œuvre · Restauration bâti ancien', '#3A5C4A', 'HC', '1946', ARRAY['EPV','GMH'], '26, rue Henri Regnault, 92150 Suresnes Cedex', '+33 (0)1 45 06 83 33', 'contact@hchevalier.com', 'http://www.hchevalier.com', 'Créée en 1946, spécialisée en restauration du bâti ancien et monuments historiques — pierre de taille, maçonnerie, gros œuvre.', 'H. Chevalier réalise des travaux techniquement complexes avec son propre bureau d''appareilleurs et atelier de taille de pierre.', 'https://ateliersdefrance.com/entreprises/h-chevalier/'),
  ('Rémy Garnier', 'remy-garnier', 'France', 'Paris', 'Paris', 'France', 'Métal', 'Serrurerie décorative · Quincaillerie d''art · Ciselure · Dorure sur bronze', '#2A3F6B', 'RG', '1832', ARRAY['EPV','GMH'], '30 bis, Boulevard de la Bastille, 75012 Paris', '+33 (0)1 43 43 84 85', 'r.garnier@remygarnier.fr', 'http://www.remygarnier.fr', 'Depuis 1832, Rémy Garnier révolutionne la serrurerie d''art avec des milliers de modèles de tous les styles.', 'En bientôt 200 ans d''existence, Rémy Garnier a cumulé l''une des plus importantes collections de quincaillerie d''art du marché.', 'https://ateliersdefrance.com/entreprises/remy-garnier/'),
