insert into public.knowledge_base (title, type, description, source) values
  ('Restauration pierre de taille en site occupé : Hôtel de la Marine, Paris', 'rex', 'Intervention sur façades classées MH place de la Concorde avec bâtiment en activité. Protocoles d''échafaudage et de protection adaptés, taille de pierre en atelier avant pose.', 'H. Chevalier'),
  ('Château de Versailles : complexité logistique des chantiers MH en Île-de-France', 'rex', 'Gestion d''un chantier multi-corps d''état sur façades classées. Rôle du bureau d''appareilleurs propre à H. Chevalier pour garantir la conformité des tailles et des joints à la chaux.', 'H. Chevalier'),
  ('Techniques de staff XIXe siècle : réalisation de cornishes et rosaces à la française', 'technique', 'Méthodes de tirage de corniches au calibre, moulage de rosaces et ornements en plâtre pur ou armé. Préconisations pour assemblage sur faux-plafond et traitement des supports anciens.', 'Atelier Louis Del Boca'),
  ('Dorure à la feuille sur staff : préparation du support et choix des colles', 'bonnes_pratiques', 'Les supports en staff nécessitent une isolation de surface avant dorure. Comparatif des assiettes (mixtion vs assiette à l''eau), durées de repos et compatibilité avec l''humidité résiduelle du plâtre.', 'Atelier Louis Del Boca'),
  ('Al-Kheesa Palace (Qatar) : serrurerie décorative palatiale à grande échelle', 'rex', 'Fourniture de plusieurs centaines de pièces de quincaillerie d''art coordonnées. Adaptation des finitions (dorure, patines) aux contraintes climatiques du Moyen-Orient.', 'Rémy Garnier'),
  ('Ciselure sur bronze : processus de finition à la main et contrôle qualité', 'bonnes_pratiques', 'La ciselure est réalisée après fonte et avant patine. Outillage traditionnel (ciselets, brounissoirs) et séquençage des opérations pour éviter les reprises. Critères de réception qualité.', 'Rémy Garnier'),
  ('Église Saint-Laurent à Marseille : maçonnerie ancienne en pierres calcaires locales', 'rex', 'Spécificité des calcaires provençaux : taille plus aisée mais nécessitant des joints à la chaux aérienne. Retour sur la gestion des pathologies liées au sel marin.', 'Vivian & Cie'),
  ('Cuir de Cordoue : technique de réalisation et restauration pour boiseries de prestige', 'technique', 'Histoire et procédé du cuir de Cordoue gaufré et doré. Méthode de restauration des panneaux existants (consolidation, nettoyage, retouches dorure) et fourniture de neuf à l''identique.', 'Atelier Mériguet-Carrère');
